If yes, how can I do that? Creating a presale contract separate from the main contract is a common approach when launching a token on a decentralized finance (DeFi) platform. This allows you to manage the presale process independently while keeping the main contract focused on the token's core functionality. Here’s a step-by-step guide on how you can achieve this:

### Step 1: Define Your Smart Contracts

1. **Main Token Contract**: This will be the primary contract for your token, handling all token-related operations like minting, transferring, and burning.
2. **Presale Contract**: This contract will handle the presale process, including token sales, refunds, and managing presale participants.

### Step 2: Create the Main Token Contract

Here’s an example of a simple ERC-20 token contract in Solidity:

```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract MyToken is ERC20, Ownable {
    constructor() ERC20("MyToken", "MTK") {
        _mint(msg.sender, 1000000 * 10**decimals());
    }

    function mint(address to, uint256 amount) public onlyOwner {
        _mint(to, amount);
    }

    function burn(address from, uint256 amount) public onlyOwner {
        _burn(from, amount);
    }
}
```

### Step 3: Create the Presale Contract

Here’s an example of a presale contract that handles token sales and refunds:

```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/math/SafeMath.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract MyTokenPresale is Ownable {
    using SafeMath for uint256;

    IERC20 public token;
    uint256 public presalePrice; // Price per token in wei
    uint256 public presaleCap; // Maximum amount of tokens to be sold
    uint256 public presaleStartTime; // Start time of the presale
    uint256 public presaleEndTime; // End time of the presale
    mapping(address => uint256) public participantTokens; // Mapping of participant addresses to their purchased tokens

    constructor(
        IERC20 _token,
        uint256 _presalePrice,
        uint256 _presaleCap,
        uint256 _presaleStartTime,
        uint256 _presaleEndTime
    ) {
        token = _token;
        presalePrice = _presalePrice;
        presaleCap = _presaleCap;
        presaleStartTime = _presaleStartTime;
        presaleEndTime = _presaleEndTime;
    }

    function buyTokens(uint256 amount) public payable {
        require(block.timestamp >= presaleStartTime && block.timestamp <= presaleEndTime, "Presale is not active");
        require(amount > 0, "Amount must be greater than zero");
        require(token.balanceOf(address(this)) >= amount * presalePrice, "Insufficient funds in the contract");
        require(participantTokens[msg.sender].add(amount) <= presaleCap, "Exceeds presale cap");

        participantTokens[msg.sender] = participantTokens[msg.sender].add(amount);
        token.transferFrom(msg.sender, address(this), amount * presalePrice);
    }

    function refundTokens() public {
        require(block.timestamp > presaleEndTime, "Presale has not ended yet");
        uint256 tokens = participantTokens[msg.sender];
        participantTokens[msg.sender] = 0;
        token.transfer(msg.sender, tokens);
    }

    function withdrawFunds() public onlyOwner {
        require(block.timestamp > presaleEndTime, "Presale has not ended yet");
        uint256 balance = address(this).balance;
        payable(owner()).transfer(balance);
    }
}
```

### Step 4: Deploy and Integrate

1. **Deploy the Main Token Contract**: Deploy the main token contract to the blockchain.
2. **Deploy the Presale Contract**: Deploy the presale contract, passing the main token contract address, presale price, cap, start time, and end time as arguments.
3. **Integrate with Launchpad**: Once the presale is complete, integrate the main token contract with the launchpad platform.

### Step 5: Manage the Presale

- **Start the Presale**: Set the presale start and end times.
- **Sell Tokens**: Participants can buy tokens using the `buyTokens` function.
- **Refund Tokens**: Participants can refund their tokens if the presale ends without reaching the cap.
- **Withdraw Funds**: The owner can withdraw funds from the presale contract once the presale is over.

By following these steps, you can effectively manage a private token sale and integrate it with a launchpad platform.

