```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <algorithm>

int main() {
    std::string filename, word;
    int count = 0;

    // Prompt user to enter filename and word to search for
    std::cout << "Enter filename: ";
    std::cin >> filename;
    std::cout << "Enter word to search for: ";
    std::cin >> word;

    // Open file for reading
    std::ifstream file(filename);
    if (!file.is_open()) {
        std::cerr << "Error opening file: " << filename << std::endl;
        return 1;
    }

    // Read file line by line and count occurrences of word
    std::string line;
    while (std::getline(file, line)) {
        // Convert line to lowercase and count occurrences of word
        std::transform(line.begin(), line.end(), line.begin(), ::tolower);
        count += std::count(line.begin(), line.end(), word[0]) - std::count(line.begin(), line.end(), word[0] + ' ');

        // Check if word is present in line and increment count if so
        if (line.find(word) != std::string::npos) {
            count++;
        }
    }

    // Close file
    file.close();

    // Display total count
    std::cout << "Total occurrences of '" << word << "': " << count << std::endl;

    return 0;
}
